+      return text;
+    }
+
+    let end = lines.findIndex((line, index) => index > start && tocEnd.test(line));
+    if (end === -1) {
+      end = start + 1;
+    }
+
+    const headings = this.getHeadings(lines, start, end, options);
+    const tocLines = this.buildToc(lines[start], end < lines.length && tocEnd.test(lines[end]) ? lines[end] : '<!-- /toc -->', headings, options);
+    const output = [...lines.slice(0, start), ...tocLines, ...lines.slice(end < lines.length && tocEnd.test(lines[end]) ? end + 1 : end)].join(lineEnding);
+    return output;
+  }
