+      .replace(/!\\[[^\\]]*\\]\\([^)]*\\)/g, '')
+      .replace(/\\[\\[([^\\]|]+)(?:\\|([^\\]]*))?\\]\\]/g, (_match, target: string, display?: string) => display ?? target)
+      .replace(/\\[([^\\]]*)\\]\\([^)]*\\)/g, '$1');
+}
+
+function stripFormatting(text: string): string {
+  return text.replace(/(\\\\.)|(`+)|([*_~])/g, (_match, escaped: string) => escaped ?? '');
+}
+
+function makeAnchor(text: string): string {
+  return stripFormatting(text)
+      .toLowerCase()
+      .replace(/\\s+/g, '-')
+      .replace(/[^a-z0-9_-]/g, '')
+      .replace(/-+/g, '-')
+      .replace(/^-+|-+$/g, '');
+}
+
+function isExcluded(heading: string, exclusions: string[]): boolean {
+  const plainHeading = stripFormatting(heading);
+  return exclusions.some((exclusion) => {
+    if (exclusion.startsWith('/') && exclusion.endsWith('/') && exclusion.length > 2) {
+      try {
+        return new RegExp(exclusion.slice(1, -1), 'i').test(plainHeading);
+      } catch (_) {
+        // Treat malformed regex-like values as literals.
+      }
+    }
+    return plainHeading.localeCompare(exclusion, undefined, {sensitivity: 'accent'}) === 0;
+  });
+}
